export const scene: DialogueEntry[] = [
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "20:40。", background: Background.Chapter_7_Ch7_Act10_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "鐘樓。", background: Background.Chapter_7_Ch7_Act10_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "顧言站在鐘樓東側相鄰建築的簷下。離鐘樓底部大概三十步遠。雨比一個小時前更大了。風把雨從簷沿吹進來，打在他的臉上。他沒有擦。", background: Background.Chapter_7_Ch7_Act10_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）鐘樓。", background: Background.Chapter_7_Ch7_Act10_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）和前幾輪一樣。臨時維修單貼在塔座。黃色警戒帶拉在入口。22:22停電的流程沒有變。", background: Background.Chapter_7_Ch7_Act10_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）這些是原本就有的。", background: Background.Chapter_7_Ch7_Act10_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）我要看的不是這些。", background: Background.Chapter_7_Ch7_Act10_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）我要看的是——有沒有新增的東西。", background: Background.Chapter_7_Ch7_Act10_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他沿著鐘樓的輪廓線看了一遍。從塔座到塔頂。從東面的入口到北面的天線屋檢修門。", background: Background.Chapter_7_Ch7_Act10_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）天線屋。", background: Background.Chapter_7_Ch7_Act10_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）我告訴韓越的是——如果直播線被切，鐘樓天線屋可能能走舊廣播線作為備用傳輸點。", background: Background.Chapter_7_Ch7_Act10_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）如果韓越把這條情報洩出去了，鐘樓應該會有新增反應。針對天線屋的封鎖。校安巡邏。或者陷阱。", background: Background.Chapter_7_Ch7_Act10_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）看。", background: Background.Chapter_7_Ch7_Act10_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "天線屋的檢修門在鐘樓北面。一扇鐵門，平時用掛鎖鎖著。顧言隔著三十步的雨幕看過去——門上的掛鎖還在。門前沒有人。沒有新增的警戒帶。沒有校安。沒有臨時監控。", background: Background.Chapter_7_Ch7_Act10_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）沒有。", background: Background.Chapter_7_Ch7_Act10_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）天線屋沒有任何新增布置。", background: Background.Chapter_7_Ch7_Act10_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）鐘樓還是原本的鐘樓。22:22停電。入口封鎖。維修單。就這些。", background: Background.Chapter_7_Ch7_Act10_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）沒有因為我給韓越的那條情報，出現任何新的動作。", background: Background.Chapter_7_Ch7_Act10_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯", background: Background.Chapter_7_Ch7_Act10_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）第二條線。無反應。", background: Background.Chapter_7_Ch7_Act10_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "許星棠沒有跟來。她在主樓一樓走廊等。鐘樓周邊太開闊，兩個人同時出現太顯眼。顧言一個人來看就夠了。", background: Background.Chapter_7_Ch7_Act10_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）再確認一遍。", background: Background.Chapter_7_Ch7_Act10_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他從簷下走出來。沿著鐘樓外圍的步道走了一圈。雨打在校服上，布料吸飽了水，變沉。他沒有加快腳步。", background: Background.Chapter_7_Ch7_Act10_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "東面。入口。黃色警戒帶。維修單。和前幾輪一樣。", background: Background.Chapter_7_Ch7_Act10_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "北面。天線屋檢修門。掛鎖。沒有人。沒有新增。", background: Background.Chapter_7_Ch7_Act10_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "西面。背風側。沒有校安車。沒有臨時照明。沒有腳印——地上只有積水和落葉。", background: Background.Chapter_7_Ch7_Act10_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "南面。面向操場的方向。遠處禮堂的燈光透過雨幕，暖黃色。鐘樓南面牆上什麼都沒有。", background: Background.Chapter_7_Ch7_Act10_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）全部確認完畢。", background: Background.Chapter_7_Ch7_Act10_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）鐘樓線無新增反應。", background: Background.Chapter_7_Ch7_Act10_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）韓越沒有把情報洩出去。或者他洩出去了，但沒有人覺得需要針對天線屋做什麼。", background: Background.Chapter_7_Ch7_Act10_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）不管哪種——韓越這條線是乾淨的。", background: Background.Chapter_7_Ch7_Act10_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）嫌疑下降。", background: Background.Chapter_7_Ch7_Act10_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他走回簷下。甩了甩袖子上的水。手機震動了一下——許星棠的訊息。", background: Background.Chapter_7_Ch7_Act10_S0 },
    { characterId: CharacterId.Message, character: "訊息", dialogue: "怎麼樣。", background: Background.Chapter_7_Ch7_Act10_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯", background: Background.Chapter_7_Ch7_Act10_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他沒有回覆。他把手機收回口袋。因為他聽見了腳步聲。", background: Background.Chapter_7_Ch7_Act10_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "從主樓方向。不急。但很重。膠底鞋踩過積水的聲音。每一步都帶著一點水花。", background: Background.Chapter_7_Ch7_Act10_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "韓越從雨裡走出來。", background: Background.Chapter_7_Ch7_Act10_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "校服外罩沾灰塵的深色外套。脖子上的舞台組臨時通行證被雨打濕了，藍底白字變得有點糊。手背上的刮傷結了暗紅薄痂。他走到簷下，離顧言三步遠的地方站住。", background: Background.Chapter_7_Ch7_Act10_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他沒有看鐘樓。他看顧言。", background: Background.Chapter_7_Ch7_Act10_S0 },
    { characterId: CharacterId.HanYue, character: "韓越", dialogue: "你在看鐘樓。", background: Background.Chapter_7_Ch7_Act10_S0, portrait: Portrait.HanYue_Angry },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "嗯。", background: Background.Chapter_7_Ch7_Act10_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.HanYue, character: "韓越", dialogue: "你在看有沒有人動天線屋。", background: Background.Chapter_7_Ch7_Act10_S0, portrait: Portrait.HanYue_Angry },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯他知道了。他猜到了我在測他。", background: Background.Chapter_7_Ch7_Act10_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "嗯。", background: Background.Chapter_7_Ch7_Act10_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "韓越的下巴抬了一下。嘴唇壓緊。他的眼睛在雨裡很亮——不是那種冷的亮。是那種被刺到之後、還沒決定要不要發火的亮。", background: Background.Chapter_7_Ch7_Act10_S0 },
    { characterId: CharacterId.HanYue, character: "韓越", dialogue: "沒有。", background: Background.Chapter_7_Ch7_Act10_S0, portrait: Portrait.HanYue_Angry },
    { characterId: CharacterId.HanYue, character: "韓越", dialogue: "沒有人動天線屋。沒有新增封鎖。沒有校安。什麼都沒有。", background: Background.Chapter_7_Ch7_Act10_S0, portrait: Portrait.HanYue_Angry },
    { characterId: CharacterId.HanYue, character: "韓越", dialogue: "我沒有跟任何人說過你給我的那條情報。", background: Background.Chapter_7_Ch7_Act10_S0, portrait: Portrait.HanYue_Angry },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "我知道。", background: Background.Chapter_7_Ch7_Act10_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.HanYue, character: "韓越", dialogue: "你知道。", background: Background.Chapter_7_Ch7_Act10_S0, portrait: Portrait.HanYue_Angry },
    { characterId: CharacterId.HanYue, character: "韓越", dialogue: "你早就知道結果了。你來這裡不是為了確認。你來這裡是為了讓我自己看見——你連我都在測。", background: Background.Chapter_7_Ch7_Act10_S0, portrait: Portrait.HanYue_Angry },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "雨打在簷沿上。水簾從簷角垂下來。韓越的聲音不大，但每個字都帶著壓住的力道。像一根繃到極限的繩子，還沒斷，但已經在震。", background: Background.Chapter_7_Ch7_Act10_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）他生氣了。", background: Background.Chapter_7_Ch7_Act10_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）但不是兇手式的生氣。", background: Background.Chapter_7_Ch7_Act10_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）他像一個被同伴懷疑的人。不是被冤枉的憤怒。是——", background: Background.Chapter_7_Ch7_Act10_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）是受傷。", background: Background.Chapter_7_Ch7_Act10_S0, portrait: Portrait.GuYan_Sad },
    { characterId: CharacterId.HanYue, character: "韓越", dialogue: "你說你要救她。", background: Background.Chapter_7_Ch7_Act10_S0, portrait: Portrait.HanYue_Angry },
    { characterId: CharacterId.HanYue, character: "韓越", dialogue: "結果你第一件事，就是把她身邊的人都當兇手測。", background: Background.Chapter_7_Ch7_Act10_S0, portrait: Portrait.HanYue_Angry },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯", background: Background.Chapter_7_Ch7_Act10_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）他說得對。", background: Background.Chapter_7_Ch7_Act10_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）我沒有反駁的餘地。", background: Background.Chapter_7_Ch7_Act10_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "我不是覺得你想害她。", background: Background.Chapter_7_Ch7_Act10_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "我只是不能再用感覺排除任何人。", background: Background.Chapter_7_Ch7_Act10_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "韓越沉默了。雨聲填滿了兩個人之間的空隙。他的手插在外套口袋裡，肩膀的線條繃著。通行證在他脖子上晃了一下——風吹的。", background: Background.Chapter_7_Ch7_Act10_S0 },
    { characterId: CharacterId.HanYue, character: "韓越", dialogue: "⋯⋯", background: Background.Chapter_7_Ch7_Act10_S0, portrait: Portrait.HanYue_Worried },
    { characterId: CharacterId.HanYue, character: "韓越", dialogue: "那你最好也測你最信的那個大人。", background: Background.Chapter_7_Ch7_Act10_S0, portrait: Portrait.HanYue_Angry },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯", background: Background.Chapter_7_Ch7_Act10_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）他不知道我已經在測了。", background: Background.Chapter_7_Ch7_Act10_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）但這句話——和許星棠說的一模一樣。", background: Background.Chapter_7_Ch7_Act10_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）兩個不同的人，用不同的方式，跟我說了同一件事。", background: Background.Chapter_7_Ch7_Act10_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯我逃不掉了。", background: Background.Chapter_7_Ch7_Act10_S0, portrait: Portrait.GuYan_Sad },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "韓越等了幾秒。顧言沒有說話。韓越的表情變了——從憤怒變成了一種更冷的東西。不是恨。是失望沉到底之後剩下的那層硬殼。", background: Background.Chapter_7_Ch7_Act10_S0 },
    { characterId: CharacterId.HanYue, character: "韓越", dialogue: "這樣你滿意了？", background: Background.Chapter_7_Ch7_Act10_S0, portrait: Portrait.HanYue_Angry },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "聲音很平。平到像在念一個已經不重要的結論。", background: Background.Chapter_7_Ch7_Act10_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "顧言看著他。韓越的臉上沒有解脫。沒有「我早就說了我沒問題」的得意。也沒有「你終於相信我了」的放鬆。", background: Background.Chapter_7_Ch7_Act10_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他只是冷。", background: Background.Chapter_7_Ch7_Act10_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "像一個人被排除嫌疑之後，發現自己更想要的不是清白——而是被信任。", background: Background.Chapter_7_Ch7_Act10_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "不滿意。", background: Background.Chapter_7_Ch7_Act10_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.HanYue, character: "韓越", dialogue: "⋯⋯", background: Background.Chapter_7_Ch7_Act10_S0, portrait: Portrait.HanYue_Angry },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "但至少少錯一個人。", background: Background.Chapter_7_Ch7_Act10_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "韓越盯著他。三秒。五秒。雨打在兩個人之間的地上，水花濺起來又落下。", background: Background.Chapter_7_Ch7_Act10_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "然後韓越轉身。走了。腳步聲踩進積水裡，比來的時候重。他沒有回頭。", background: Background.Chapter_7_Ch7_Act10_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯", background: Background.Chapter_7_Ch7_Act10_S0, portrait: Portrait.GuYan_Sad },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）他沒有高興。", background: Background.Chapter_7_Ch7_Act10_S0, portrait: Portrait.GuYan_Sad },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）被排除嫌疑的人沒有高興。", background: Background.Chapter_7_Ch7_Act10_S0, portrait: Portrait.GuYan_Sad },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）這說明他不是兇手。兇手被排除之後會鬆一口氣。他沒有。他只是更冷了。", background: Background.Chapter_7_Ch7_Act10_S0, portrait: Portrait.GuYan_Sad },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）記下來。", background: Background.Chapter_7_Ch7_Act10_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）鐘樓線無新增反應。韓越嫌疑下降。", background: Background.Chapter_7_Ch7_Act10_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）他沒有靠近鐘樓。沒有洩漏情報。沒有新增布置。", background: Background.Chapter_7_Ch7_Act10_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）第二條線。乾淨。", background: Background.Chapter_7_Ch7_Act10_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "顧言靠在簷柱上。雨從他頭髮上滴下來，順著鼻樑滑到下巴。他沒有擦。", background: Background.Chapter_7_Ch7_Act10_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）兩條線了。", background: Background.Chapter_7_Ch7_Act10_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）林主任。命中。但是執行者。他在聽命。", background: Background.Chapter_7_Ch7_Act10_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）韓越。乾淨。沒有反應。沒有洩漏。", background: Background.Chapter_7_Ch7_Act10_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）第三條線。", background: Background.Chapter_7_Ch7_Act10_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）21:20。醫務室。", background: Background.Chapter_7_Ch7_Act10_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯", background: Background.Chapter_7_Ch7_Act10_S0, portrait: Portrait.GuYan_Sad },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）邵叔。", background: Background.Chapter_7_Ch7_Act10_S0, portrait: Portrait.GuYan_Sad },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）我不想知道答案。", background: Background.Chapter_7_Ch7_Act10_S0, portrait: Portrait.GuYan_Sad },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）但只剩這一條了。", background: Background.Chapter_7_Ch7_Act10_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他從簷下走出來。雨打在他的後背上。校服已經濕透了，貼在身上，很冷。", background: Background.Chapter_7_Ch7_Act10_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "鐘樓在身後。雨霧裡只剩一個模糊的輪廓。和早上看到的一樣。和每一輪看到的一樣。", background: Background.Chapter_7_Ch7_Act10_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "但這一次，顧言知道——鐘樓不是敵人。鐘樓只是一棟老樓。22:22會停電。入口會被封鎖。就這樣。", background: Background.Chapter_7_Ch7_Act10_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "敵人不會站在鐘樓裡。", background: Background.Chapter_7_Ch7_Act10_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "敵人會站在他最不想看的地方。", background: Background.Chapter_7_Ch7_Act10_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "21:20。", background: Background.Chapter_7_Ch7_Act10_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "醫務室。", background: Background.Chapter_7_Ch7_Act10_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "第三條線。", background: Background.Chapter_7_Ch7_Act10_S0 },
];
